        self._seen_message_keys_by_chat: Dict[int, Tuple[set, deque]] = {}

        # UI performance: batch bubble rendering so busy chats don't freeze the UI.
        self._ui_live_bubble_queue: Deque[Tuple[int, str, str, str, bool, str]] = deque()
